// CODE NODE: CLEAN INTERNAL DATA (VERSI FIX)
const results = [];

for (const item of $input.all()) {
  const json = item.json;

  // 1. Ambil Tanggal & Format ke YYYY-MM-DD
  const rawDate = (json['Tanggal Transaksi'] || '').toString().trim();
  const dateParts = rawDate.split('/');

  // Jika format tanggal salah/kosong, skip baris ini
  if (dateParts.length !== 3) continue;

  const cleanDate = `${dateParts[2]}-${dateParts[1]}-${dateParts[0]}`;

  // 2. Ambil Nominal & Hapus karakter non-angka (Rp, titik, koma)
  const rawAmount = (json['Jumlah (IDR)'] || '0').toString();
  const cleanAmount = parseInt(rawAmount.replace(/[^0-9]/g, ''));

  // 3. Buat Match Key untuk pencocokan
  const matchKey = `${cleanDate}_${cleanAmount}`;

  results.push({
    json: {
      ...json,
      clean_date: cleanDate,
      clean_amount: cleanAmount,
      match_key: matchKey,
      sumber: 'Internal'
    }
  });
}

return results;

// CODE NODE: CLEAN BANK DATA (REVISI)
const results = [];

for (const item of $input.all()) {
  const json = item.json;

  // 1. Bersihkan Tanggal
  const rawDate = (json['Tanggal Bank'] || '').toString().trim();
  const dateParts = rawDate.split('/');
  if (dateParts.length !== 3) continue;

  const cleanDate = `${dateParts[2]}-${dateParts[1]}-${dateParts[0]}`;

  // 2. PENTING: Bersihkan Angka (Hapus titik ribuan Rupiah)
  const rawAmount = (json['Jumlah (IDR)'] || '0').toString();
  // Regex ini menghapus apa saja yang bukan angka (termasuk titik/koma)
  const cleanAmount = parseInt(rawAmount.replace(/[^0-9]/g, ''));

  // 3. Buat Match Key
  const matchKey = `${cleanDate}_${cleanAmount}`;

  results.push({
    json: {
      ...json,
      clean_date: cleanDate,
      clean_amount: cleanAmount,
      match_key: matchKey,
      sumber: 'Bank'
    }
  });
}

return results;

// CODE NODE: ANALISA REKONSILIASI LENGKAP (tanpa Union)
const items = $input.all();
const grouped = {};

// 1. Group by match_key
for (const item of items) {
  const key = item.json.match_key;
  if (!grouped[key]) {
    grouped[key] = { sources: [], details: [] };
  }
  grouped[key].sources.push(item.json.sumber);
  grouped[key].details.push(item.json);
}

// 2. Bangun hasil analisa
const results = [];
for (const [key, group] of Object.entries(grouped)) {
  const hasInternal = group.sources.includes('Internal');
  const hasBank = group.sources.includes('Bank');

  let status, pesan, priority;
  if (hasInternal && hasBank) {
    status = 'MATCHED';
    pesan = '✅ Data klop (Cocok).';
    priority = 'Low';
  } else if (hasInternal && !hasBank) {
    status = 'MISSING IN BANK';
    pesan = '⚠️ Tercatat di Internal, tapi tidak ada di Bank.';
    priority = 'High';
  } else if (!hasInternal && hasBank) {
    status = 'UNRECORDED INTERNAL';
    pesan = '⚠️ Ada di Bank, tapi tidak tercatat di Internal.';
    priority = 'Medium';
  }

  const internal = group.details.find(d => d.sumber === 'Internal');
  const bank = group.details.find(d => d.sumber === 'Bank');
  const refDate = (internal || bank)?.clean_date;
  const amount = (internal || bank)?.clean_amount;

  results.push({
    json: {
      Tanggal: refDate,
      Nominal: amount,
      Status: status,
      Pesan: pesan,
      Prioritas: priority,
      Internal_ID: internal?.['ID Referensi'] || 'N/A',
      Bank_ID: bank?.['ID Transaksi Bank'] || 'N/A',
      Deskripsi: internal?.Deskripsi || bank?.['Deskripsi Transaksi'] || '-',
      Match_Key: key,
      Sources: group.sources.join(' + ')
    }
  });
}

return results;
